import{_ as a,o as i,c as e,a2 as h}from"./chunks/framework.CHSDihme.js";const r=JSON.parse('{"title":"全局使用（任意目录启动）","description":"","frontmatter":{},"headers":[],"relativePath":"guide/global-usage.md","filePath":"guide/global-usage.md","lastUpdated":1780729781000}'),t={name:"guide/global-usage.md"};function n(l,s,p,d,o,k){return i(),e("div",null,[...s[0]||(s[0]=[h(`<h1 id="全局使用任意目录启动" tabindex="-1">全局使用（任意目录启动） <a class="header-anchor" href="#全局使用任意目录启动" aria-label="Permalink to &quot;全局使用（任意目录启动）&quot;">​</a></h1><p>如果你希望在任意项目目录直接运行 <code>claude-haha</code>，可以通过以下方式配置。配置完成后，<code>claude-haha</code> 会自动识别你当前所在的工作目录。</p><h2 id="macos--linux" tabindex="-1">macOS / Linux <a class="header-anchor" href="#macos--linux" aria-label="Permalink to &quot;macOS / Linux&quot;">​</a></h2><p>在 <code>~/.bashrc</code> 或 <code>~/.zshrc</code> 中添加：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 方式一：添加 PATH（推荐）</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> PATH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/path/to/claude-code-haha/bin:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$PATH</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 方式二：alias</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">alias</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> claude-haha</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/path/to/claude-code-haha/bin/claude-haha&quot;</span></span></code></pre></div><p>然后重新加载配置：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">source</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.bashrc</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 或 source ~/.zshrc</span></span></code></pre></div><h2 id="windows-git-bash" tabindex="-1">Windows (Git Bash) <a class="header-anchor" href="#windows-git-bash" aria-label="Permalink to &quot;Windows (Git Bash)&quot;">​</a></h2><p>在 <code>~/.bashrc</code> 中添加：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> PATH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/path/to/claude-code-haha/bin:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$PATH</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span></code></pre></div><h3 id="windows--wsl-工具链" tabindex="-1">Windows + WSL 工具链 <a class="header-anchor" href="#windows--wsl-工具链" aria-label="Permalink to &quot;Windows + WSL 工具链&quot;">​</a></h3><p>如果 <code>claude-haha</code> 运行在 Windows / Git Bash，但 Node、Python、uv、bun 等工具主要安装在 WSL 里，可以显式通过 WSL 调用：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wsl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lc</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;node --version &amp;&amp; python3 --version&#39;</span></span></code></pre></div><p>cc-haha 会在检测到 <code>wsl</code> / <code>wsl.exe</code> 调用时自动设置 <code>MSYS2_ARG_CONV_EXCL=*</code>，避免 Git Bash 把 <code>/home/...</code> 这类 WSL 路径错误转换成 <code>C:/Program Files/Git/home/...</code>。</p><p>如果你想让 Bash 工具默认进入 WSL，可以在启动前设置：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CLAUDE_CODE_SHELL_PREFIX</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;wsl -e bash -lc&#39;</span></span></code></pre></div><p>Computer Use 仍然控制 Windows 桌面应用，WSL 内的 CLI 工具不需要写入 <code>computer-use-config.json</code>。如果只使用 WSL 工具链、不需要桌面控制，建议使用 <code>--no-computer-use</code> 或在 Settings &gt; Computer Use 中关闭它。</p><h2 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h2><p>配置完成后，进入任意项目目录测试：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/your-other-project</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude-haha</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 启动后询问「当前目录是什么？」，应显示 ~/your-other-project</span></span></code></pre></div>`,20)])])}const g=a(t,[["render",n]]);export{r as __pageData,g as default};
